import React, { useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useDropzone } from 'react-dropzone';
import toast from 'react-hot-toast';
import { baiDangAPI } from '../services/api';
import './TaoBaiDang.css';

export default function TaoBaiDang() {
  const navigate = useNavigate();
  const [form, setForm] = useState({ moTa: '', noiDung: '', giaTien: '', diaChi: '', maPhong: '' });
  const [files, setFiles] = useState([]);
  const [previews, setPreviews] = useState([]);
  const [submitting, setSubmitting] = useState(false);

  const onDrop = useCallback(accepted => {
    setFiles(prev => [...prev, ...accepted]);
    setPreviews(prev => [...prev, ...accepted.map(f => URL.createObjectURL(f))]);
  }, []);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop, accept: { 'image/*': [] }, multiple: true,
  });

  const set = (k, v) => setForm(f => ({...f, [k]: v}));

  const handleSubmit = async e => {
    e.preventDefault();
    if (!form.moTa || !form.giaTien || !form.diaChi) { toast.error('Vui lòng điền đầy đủ thông tin bắt buộc'); return; }
    setSubmitting(true);
    try {
      const res = await baiDangAPI.tao({
        moTa: form.moTa, noiDung: form.noiDung,
        giaTien: parseFloat(form.giaTien), diaChi: form.diaChi,
        maPhong: form.maPhong ? parseInt(form.maPhong) : undefined,
      });
      const maBaiDang = res.data.data.maBaiDang;
      // Upload images if any
      if (files.length > 0) {
        const fd = new FormData();
        files.forEach(f => fd.append('files', f));
        await baiDangAPI.uploadAnh(maBaiDang, fd);
      }
      toast.success('Đăng bài thành công!');
      navigate(`/bai-dang/${maBaiDang}`);
    } catch (e) {
      toast.error(e.response?.data?.message || 'Đăng bài thất bại');
    }
    setSubmitting(false);
  };

  return (
    <div className="container page-wrapper">
      <div className="tao-baidang-wrapper">
        <div className="card">
          <div className="card-header">📝 Đăng tin tìm bạn ở ghép</div>
          <div className="card-body">
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label className="form-label">Tiêu đề / Mô tả ngắn <span style={{color:'red'}}>*</span></label>
                <input className="form-control" placeholder="VD: Cần tìm 1 bạn nữ ghép phòng Q1, giá 3tr/tháng"
                  value={form.moTa} onChange={e => set('moTa', e.target.value)} required />
              </div>

              <div className="grid-2">
                <div className="form-group">
                  <label className="form-label">Giá thuê (đ/tháng) <span style={{color:'red'}}>*</span></label>
                  <input className="form-control" type="number" placeholder="3000000"
                    value={form.giaTien} onChange={e => set('giaTien', e.target.value)} required />
                </div>
                <div className="form-group">
                  <label className="form-label">Mã phòng (nếu có)</label>
                  <input className="form-control" type="number" placeholder="ID phòng đã tạo"
                    value={form.maPhong} onChange={e => set('maPhong', e.target.value)} />
                </div>
              </div>

              <div className="form-group">
                <label className="form-label">Địa chỉ <span style={{color:'red'}}>*</span></label>
                <input className="form-control" placeholder="Số nhà, đường, phường, quận, thành phố"
                  value={form.diaChi} onChange={e => set('diaChi', e.target.value)} required />
              </div>

              <div className="form-group">
                <label className="form-label">Nội dung chi tiết</label>
                <textarea className="form-control" rows={5}
                  placeholder="Mô tả về phòng, tiện nghi, yêu cầu bạn ghép, thời gian có thể vào ở..."
                  value={form.noiDung} onChange={e => set('noiDung', e.target.value)} />
              </div>

              {/* Image upload */}
              <div className="form-group">
                <label className="form-label">Hình ảnh phòng</label>
                <div {...getRootProps()} className={`dropzone ${isDragActive ? 'active' : ''}`}>
                  <input {...getInputProps()} />
                  <div className="dropzone-content">
                    <span style={{ fontSize: 40 }}>📸</span>
                    <p>{isDragActive ? 'Thả ảnh vào đây...' : 'Kéo thả hoặc click để chọn ảnh'}</p>
                    <p style={{ fontSize: 12, color: 'var(--text-muted)' }}>Hỗ trợ JPG, PNG, WEBP</p>
                  </div>
                </div>
                {previews.length > 0 && (
                  <div className="preview-grid">
                    {previews.map((src, i) => (
                      <div key={i} className="preview-item">
                        <img src={src} alt="" />
                        <button type="button" className="preview-remove"
                          onClick={() => { setFiles(fs => fs.filter((_,j) => j!==i)); setPreviews(ps => ps.filter((_,j) => j!==i)); }}>
                          ✕
                        </button>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              <div style={{ display:'flex', gap: 12 }}>
                <button type="submit" className="btn btn-primary btn-lg" disabled={submitting} style={{ flex:1 }}>
                  {submitting ? '⏳ Đang đăng...' : '🚀 Đăng bài ngay'}
                </button>
                <button type="button" className="btn btn-secondary btn-lg" onClick={() => navigate(-1)}>Hủy</button>
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}
